from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about an athlete (or related entities) into a single fluent sentence.
    """
    if not triples:
        return ""

    # Build entity relationships to create connected sentences
    entity_info = {}
    all_subjects = set()
    all_objects = set()

    for triple in triples:
        subj = triple.subject
        pred = triple.predicate.lower()
        obj = triple.object

        all_subjects.add(subj)
        all_objects.add(obj)

        if subj not in entity_info:
            entity_info[subj] = []
        entity_info[subj].append((pred, obj))

    # Find main subject - prefer athletes over teams/organizations
    # Check if any subject looks like a person (has common name patterns)
    athlete_keywords = ["club", "currentclub", "currentteam", "formerTeam", "birthDate", "birthPlace",
                        "height", "weight", "position", "playerNumber", "draft"]

    main_subject = None
    max_score = -1

    for subj in entity_info.keys():
        score = len(entity_info[subj])
        # Boost score if subject is connected to athlete-related predicates
        for pred, _ in entity_info[subj]:
            if pred in athlete_keywords:
                score += 2
        # Penalize team/organization names (usually shorter, have common patterns)
        if "FC" in subj or "Club" in subj or "Team" in subj or "Dolphins" in subj:
            score -= 1

        if score > max_score:
            max_score = score
            main_subject = subj

    # Build a chain of connected clauses using entity linking
    processed_triples = set()

    def get_clause_text(pred, obj):
        """Convert a triple to natural language text"""
        if pred == "birthDate":
            return f"was born on {obj}"
        elif pred == "birthYear":
            return f"was born in {obj}"
        elif pred == "birthPlace":
            return f"was born in {obj}"
        elif pred == "height":
            return f"measures {obj} in height"
        elif pred == "weight":
            return f"weighs {obj}"
        elif pred == "league":
            return f"plays in {obj}"
        elif pred == "club":
            return f"plays for {obj}"
        elif pred == "currentclub":
            return f"currently plays for {obj}"
        elif pred == "currentteam":
            return f"currently plays for {obj}"
        elif pred == "formerTeam":
            return f"previously played for {obj}"
        elif pred == "position":
            # Position can be a league or a playing position - check context
            if any(term in obj.lower() for term in ["league", "serie", "premier", "division"]):
                return f"plays in {obj}"
            return f"plays as a {obj}"
        elif pred == "manager":
            return f"is managed by {obj}"
        elif pred == "coach":
            return f"is coached by {obj}"
        elif pred == "owner":
            return f"is owned by {obj}"
        elif pred == "city":
            return f"is based in {obj}"
        elif pred == "country":
            return f"comes from {obj}"
        elif pred == "isPartOf":
            return f"part of {obj}"
        elif pred == "season":
            return f"season is {obj}"
        elif pred == "foundingDate":
            return f"founded on {obj}"
        elif pred == "utcOffset":
            return f"UTC offset is {obj}"
        elif pred == "timeZone":
            return f"time zone is {obj}"
        elif pred == "areaTotal":
            return f"area is {obj}"
        elif pred == "demonym":
            return f"residents are called {obj}"
        elif pred == "language":
            return f"the official language is {obj}"
        elif pred == "officialLanguage":
            return f"the official language is {obj}"
        elif pred == "anthem":
            return f"the national anthem is {obj}"
        elif pred == "leader":
            return f"the leader is {obj}"
        elif pred == "leaderTitle":
            return f"the leader title is {obj}"
        elif pred == "mostChampions":
            return f"the team with the most championships is {obj}"
        elif pred == "currency":
            return f"the currency is {obj}"
        elif pred == "draftTeam":
            return f"drafted by {obj}"
        elif pred == "draftPick":
            return f"draft pick is {obj}"
        elif pred == "draftRound":
            return f"draft round is {obj}"
        elif pred == "draftYear":
            return f"draft year is {obj}"
        elif pred == "playerNumber":
            return f"player number is {obj}"
        elif pred == "college":
            return f"college is {obj}"
        elif pred == "debutTeam":
            return f"debuted with {obj}"
        elif pred == "activeYearsStartYear":
            return f"active since {obj}"
        elif pred == "universityTeam":
            return f"university team is {obj}"
        elif pred == "stadium":
            return f"stadium is {obj}"
        elif pred == "generalManager":
            return f"general manager is {obj}"
        elif pred == "chairman":
            return f"chairman is {obj}"
        elif pred == "deathPlace":
            return f"died in {obj}"
        elif pred == "ethnicGroup":
            return f"has ethnic group {obj}"
        else:
            return f"{pred}: {obj}"

    # Group triples by predicate type for the main subject to handle multiple values
    predicate_groups = {}
    for pred, obj in entity_info.get(main_subject, []):
        if pred not in predicate_groups:
            predicate_groups[pred] = []
        predicate_groups[pred].append(obj)
        processed_triples.add((main_subject, pred, obj))

    # Now find and connect related entities (when one object is another subject)
    connected_clauses = []
    for subj in entity_info.keys():
        if subj == main_subject:
            continue
        for pred, obj in entity_info[subj]:
            if (subj, pred, obj) not in processed_triples:
                # Check if this subject is referenced by the main subject
                is_referenced = False
                for main_pred, main_obj in entity_info.get(main_subject, []):
                    if main_obj == subj:
                        is_referenced = True
                        break

                if is_referenced:
                    # Create a relative clause linking back to main subject
                    clause = get_clause_text(pred, obj)
                    # For team-related predicates, use different phrasing
                    if pred in ["club", "currentclub", "currentteam", "formerTeam"]:
                        connected_clauses.append(f"which is {obj}")
                    else:
                        connected_clauses.append(f"which {clause.lower()}")
                else:
                    clause = get_clause_text(pred, obj)
                    connected_clauses.append(clause)
                processed_triples.add((subj, pred, obj))

    # Build the final sentence - ALL information in ONE complex sentence
    main_clauses = []

    # Process grouped predicates for better natural language
    for pred, objects in predicate_groups.items():
        if len(objects) == 1:
            clause = get_clause_text(pred, objects[0])
            main_clauses.append(clause)
        else:
            # Handle multiple values for the same predicate more naturally
            if pred in ["club", "currentclub", "currentteam", "formerTeam"]:
                # For clubs/teams, list them together
                objects_text = " and ".join(objects)
                if pred == "club":
                    main_clauses.append(f"plays for {objects_text}")
                elif pred == "currentclub" or pred == "currentteam":
                    main_clauses.append(f"currently plays for {objects_text}")
                elif pred == "formerTeam":
                    main_clauses.append(f"previously played for {objects_text}")
            else:
                # For other predicates, use comma-separated list
                objects_text = ", ".join(objects)
                base_clause = get_clause_text(pred, objects[0])
                # Replace the object with the combined list
                if " " in objects[0]:
                    main_clauses.append(base_clause.replace(objects[0], objects_text))
                else:
                    main_clauses.append(f"{base_clause.split()[0]} {objects_text}")

    # Build the final sentence
    if main_clauses:
        # Connect main clauses with commas and 'and'
        base = f"{main_subject} {main_clauses[0]}"
        for clause in main_clauses[1:-1]:
            base += f", {clause}"
        if len(main_clauses) > 1:
            base += f", and {main_clauses[-1]}"

        # Append connected clauses using relative clauses
        if connected_clauses:
            for i, clause in enumerate(connected_clauses):
                if i == 0:
                    base += f", which {clause.lower()}"
                else:
                    base += f", and {clause.lower()}"

        sentence = base + "."
    else:
        # If no main clauses, try to create a sentence from connected clauses
        if connected_clauses:
            sentence = f"{main_subject} {connected_clauses[0].lower()}."
            for clause in connected_clauses[1:]:
                sentence += f", and {clause.lower()}"
        else:
            sentence = f"{main_subject}."

    # Capitalize first character
    return sentence[0].upper() + sentence[1:]

# EVOLVE-BLOCK-END

